template:
:doodle {
  @grid: 1 / 100vw 100vh;
  background: #05070a;
  overflow: hidden;
}

@size: 100%;
background-image: @doodle(
  @grid: 1x50 / 100% 100%;
  :after {
    content: '';
    @size: 100vw 4px;
    position: absolute;
    left: -50%;
    top: @r(-10%, 110%);
    background: linear-gradient(to right, transparent, @p(#6a11cb, #2575fc, #ff00cc, #00d2ff), transparent);
    filter: blur(@r(5px, 15px));
    opacity: @r(0.2, 0.5);
    transform: rotate(@r(-15deg, 15deg));
    animation: silk-flow @r(15s, 30s) ease-in-out infinite alternate;
    animation-delay: -@r(20s);
  }
);

@keyframes silk-flow {
  0% { transform: translateY(-30px) rotate(@r(-5deg, 5deg)) scaleX(1); }
  100% { transform: translateY(30px) rotate(@r(-20deg, 20deg)) scaleX(1.3); }
}

:doodle {
  @grid: 1 / 100vw 100vh;
  background: #02040a;
  overflow: hidden;
}
background: 
  radial-gradient(circle at @r(0%, 100%) @r(0%, 100%), @p(#00d2ff, #3a7bd5, #6a11cb, #2575fc, #ff00cc) 0%, transparent @r(40%, 80%)),
  radial-gradient(circle at @r(0%, 100%) @r(0%, 100%), @p(#00f2fe, #4facfe, #43e97b, #fa709a) 0%, transparent @r(30%, 70%));
filter: blur(@r(60px, 100px));
opacity: @r(0.3, 0.6);
animation: aura-move @r(20s, 45s) linear infinite alternate;
@keyframes aura-move {
  0% { transform: translate(-15%, -15%) scale(1.2) rotate(0deg); }
  100% { transform: translate(15%, 15%) scale(1.6) rotate(20deg); }
}

:doodle {
  @grid: 1 / 100vw 100vh;
  background: #080a0f;
}
@content: @svg(
  viewBox: 0 0 100 100;
  preserveAspectRatio: none;
  path*200 {
    stroke: hsla(@calc(200 + @n), 80%, 70%, @r(0.2, 0.6));
    stroke-width: @r(0.1, 0.4);
    fill: none;
    d: M @r(100) @r(100) Q @r(100) @r(100) @r(100) @r(100);
    animation: spin @r(15s, 40s) linear infinite;
  }
);
@keyframes spin { from { transform: rotate(0); } to { transform: rotate(360deg); } }

:doodle {
  @grid: 1 / 100vw 100vh;
  background: #05070a;
}
@content: @svg(
  viewBox: 0 0 100 100;
  preserveAspectRatio: none;
  line*200 {
    draw: @r(5s, 15s);
    opacity: @r(0.1, 0.4);
    stroke: @p(#aeacfb, #ffffff, #4facfe);
    stroke-width: .05;
    x1: @r(100); y1: @r(100);
    x2: @calc(@x1 + @r(-20, 20));
    y2: @calc(@y1 + @r(-20, 20));
  }
  circle*120 {
    r: @r(0.1, 0.4);
    cx: @r(100); cy: @r(100);
    fill: #fff;
    animation: twinkle @r(2s, 6s) ease-in-out infinite alternate;
  }
);
@keyframes twinkle { 0% { opacity: 0.2; transform: scale(0.8); } 100% { opacity: 1; transform: scale(1.5); } }

:doodle {
  @grid: 1x25 / 100vw 100vh;
  overflow: hidden;
}
@size: @r(150px, 400px);
background: rgba(255, 255, 255, @r(0.03, 0.1));
filter: blur(@r(2px, 8px));
border: 1px solid rgba(255, 255, 255, 0.05);
border-radius: @r(10px, 40px);
position: absolute;
left: @r(-20%, 120%);
top: @r(-20%, 120%);
animation: drift @r(20s, 60s) linear infinite;
@keyframes drift {
  0% { transform: translate(0, 0) rotate(0deg); opacity: 0; }
  20% { opacity: 0.6; }
  80% { opacity: 0.6; }
  100% { transform: translate(@r(-400px, 400px), @r(-400px, 400px)) rotate(120deg); opacity: 0; }
}

:doodle {
  @grid: 1x40 / 100vw 100vh;
}
:after {
  content: @p('01', '10', '11', '00', '><', '{}', '[]', '/*');
  color: #2ecc71;
  font-family: monospace;
  font-size: @r(14px, 22px);
  position: absolute;
  left: @r(0%, 100%);
  top: -10vh;
  text-shadow: 0 0 10px #2ecc71;
  animation: rain @r(2s, 8s) linear infinite;
}
@keyframes rain { to { transform: translateY(115vh); opacity: 0; } }

:doodle {
  @grid: 1x30 / 100vw 100vh;
}
@size: @r(2px, 4px) @r(150px, 450px);
background: linear-gradient(180deg, hsla(0, 0%, 100%, @r(0.8, 1)), transparent);
border-radius: 50%;
filter: drop-shadow(0 0 10px #fff);
position: absolute;
left: @r(-10%, 110%);
top: -50vh;
transform: rotate(155deg);
animation: fall @r(3s, 10s) linear infinite;
@keyframes fall {
  from { transform: translateY(0) rotate(155deg); opacity: 1; }
  to { transform: translateY(150vh) rotate(155deg); opacity: 0; }
}

:doodle {
  @grid: 1 / 100vw 100vh;
  background: #0a0e14;
  overflow: hidden;
}
background-image: @doodle(
  @grid: 8 / 100% 100%;
  background: hsla(@r(360), 70%, 60%, 0.1);
  border-radius: @r(30%, 70%) @r(30%, 70%) @r(30%, 70%) @r(30%, 70%);
  transform: scale(@r(1, 2)) translate(@r(-50%, 50%), @r(-50%, 50%));
  filter: blur(@r(30px, 60px));
  animation: flow @r(25s, 50s) ease-in-out infinite alternate;
);
@keyframes flow { to { transform: scale(@r(2, 3)) translate(@r(-30%, 30%), @r(-30%, 30%)) rotate(45deg); } }

:doodle {
  @grid: 20 / 100vw 100vh;
}
border-left: 1px solid hsla(@r(200, 260), 70%, 60%, @r(0.1, 0.4));
border-top: 1px solid hsla(@r(200, 260), 70%, 60%, @r(0.1, 0.4));
@random(.1) {
  background: linear-gradient(hsla(@r(360), 80%, 70%, 0.4), transparent);
  box-shadow: 0 0 15px hsla(@lr, 80%, 70%, 0.2);
  animation: glow @r(3s, 6s) ease-in-out infinite alternate;
}
@keyframes glow { 0% { opacity: 0.3; } 100% { opacity: 1; } }

:doodle {
  @grid: 10x8 / 100vw 100vh;
}
@size: @r(50px, 120px);
position: absolute;
left: @r(0%, 100%); top: @r(0%, 100%);
@content: @p('🚀', '🪐', '👾', '🎨', '💡', '🤖', 'H', 'E', 'C', 'T', 'O', 'R');
font-size: @r(40px, 80px);
color: @p(#ffbe0b, #fb5607, #ff006e, #8338ec, #3a86ff);
text-shadow: 0 0 20px rgba(255,255,255,0.3);
animation: bounce @r(4s, 8s) ease-in-out infinite;
@keyframes bounce { 0%, 100% { transform: translateY(0) rotate(0); } 50% { transform: translateY(-60px) rotate(@r(-20deg, 20deg)); } }
:hover { transform: scale(1.6) rotate(15deg); z-index: 100; }
